CREATE VIEW `ads_competitor_read_video_app_perf_download_ed_view` (`dt` COMMENT "开始日期", `country_code` COMMENT "国家码", `mt` COMMENT "终端", `app_name` COMMENT "产品名称", `product_id` COMMENT "产品id", `corever` COMMENT "corever", `lang` COMMENT "语言", `app_tps` COMMENT "产品类型，read:阅读，short_video:海外短剧", `granularity` COMMENT "时间维度", `end_date` COMMENT "结束日期", `est_organic_download` COMMENT "自然下载量", `est_organic_featured_download` COMMENT "自然下载量", `est_organic_search_download` COMMENT "自然搜索下载量", `est_paid_ads_download` COMMENT "付费广告下载量", `est_paid_channel_download` COMMENT "付费频道下载量", `est_paid_search_download` COMMENT "付费搜索下载量", `est_download` COMMENT "下载", `est_revenue` COMMENT "收入", `est_cumulative_download` COMMENT "累计下载", `company_est_cumulative_download` COMMENT "公司所有app累计下载", `est_cumulative_revenue` COMMENT "累计收入", `company_est_cumulative_revenue` COMMENT "公司所有app累计收入", `est_average_active_users` COMMENT "活跃用户", `est_usage_penetration` COMMENT "使用行为渗透率", `est_average_session_per_user` COMMENT "每用户平均会话数量", `est_average_session_duration` COMMENT "平均每次会话时长", `est_average_time_per_user` COMMENT "每用户平均用时", `est_total_time` COMMENT "总用时", `est_install_base` COMMENT "装机量", `est_install_penetration` COMMENT "安装渗透率", `est_open_rate` COMMENT "打开率")
COMMENT "竞品分析-阅读与海外短剧下载量信息表" AS SELECT `a`.`dt`, `a`.`country_code`, `a`.`mt`, `a`.`app_name`, `b`.`product_id`, `b`.`corever`, `b`.`lang`, `b`.`app_tps`, `a`.`granularity`, `a`.`end_date`, `a`.`est_organic_download`, `a`.`est_organic_featured_download`, `a`.`est_organic_search_download`, `a`.`est_paid_ads_download`, `a`.`est_paid_channel_download`, `a`.`est_paid_search_download`, `a`.`est_download`, `a`.`est_revenue`, `a`.`est_cumulative_download`, `a`.`company_est_cumulative_download`, `a`.`est_cumulative_revenue`, `a`.`company_est_cumulative_revenue`, `a`.`est_average_active_users`, `a`.`est_usage_penetration`, `a`.`est_average_session_per_user`, `a`.`est_average_session_duration`, `a`.`est_average_time_per_user`, `a`.`est_total_time`, `a`.`est_install_base`, `a`.`est_install_penetration`, `a`.`est_open_rate`
FROM (SELECT `dws`.`dws_competitor_app_perf_download_ed`.`dt`, `dws`.`dws_competitor_app_perf_download_ed`.`country_code`, CASE WHEN (`dws`.`dws_competitor_app_perf_download_ed`.`device_code` = 'ios-all') THEN 1 WHEN (`dws`.`dws_competitor_app_perf_download_ed`.`device_code` = 'android-all') THEN 4 ELSE `dws`.`dws_competitor_app_perf_download_ed`.`device_code` END AS `mt`, lower(trim(CASE WHEN (`dws`.`dws_competitor_app_perf_download_ed`.`product_name` LIKE '%-%') THEN (split_part(`dws`.`dws_competitor_app_perf_download_ed`.`product_name`, '-', 1)) WHEN (`dws`.`dws_competitor_app_perf_download_ed`.`product_name` LIKE '%:%') THEN (split_part(`dws`.`dws_competitor_app_perf_download_ed`.`product_name`, ':', 1)) ELSE `dws`.`dws_competitor_app_perf_download_ed`.`product_name` END)) AS `app_name`, `dws`.`dws_competitor_app_perf_download_ed`.`granularity`, `dws`.`dws_competitor_app_perf_download_ed`.`end_date`, `dws`.`dws_competitor_app_perf_download_ed`.`est_organic_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_organic_featured_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_organic_search_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_paid_ads_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_paid_channel_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_paid_search_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_revenue`, `dws`.`dws_competitor_app_perf_download_ed`.`est_cumulative_download`, `dws`.`dws_competitor_app_perf_download_ed`.`company_est_cumulative_download`, `dws`.`dws_competitor_app_perf_download_ed`.`est_cumulative_revenue`, `dws`.`dws_competitor_app_perf_download_ed`.`company_est_cumulative_revenue`, `dws`.`dws_competitor_app_perf_download_ed`.`est_average_active_users`, `dws`.`dws_competitor_app_perf_download_ed`.`est_usage_penetration`, `dws`.`dws_competitor_app_perf_download_ed`.`est_average_session_per_user`, `dws`.`dws_competitor_app_perf_download_ed`.`est_average_session_duration`, `dws`.`dws_competitor_app_perf_download_ed`.`est_average_time_per_user`, `dws`.`dws_competitor_app_perf_download_ed`.`est_total_time`, `dws`.`dws_competitor_app_perf_download_ed`.`est_install_base`, `dws`.`dws_competitor_app_perf_download_ed`.`est_install_penetration`, `dws`.`dws_competitor_app_perf_download_ed`.`est_open_rate`
FROM `dws`.`dws_competitor_app_perf_download_ed`
WHERE (`dws`.`dws_competitor_app_perf_download_ed`.`company_name` = 'Changdu') AND (`dws`.`dws_competitor_app_perf_download_ed`.`product_name` NOT IN ('Teller-Chat Stories MoboReader'))) `a` LEFT OUTER JOIN (SELECT lower(trim(`dim`.`dim_applications`.`remark`)) AS `app_name`, `dim`.`dim_applications`.`corever`, `dim`.`dim_applications`.`lang`, `dim`.`dim_applications`.`product_id`, `dim`.`dim_applications`.`app_tps`
FROM `dim`.`dim_applications`
WHERE ((`dim`.`dim_applications`.`product_id` = 3366) AND (`dim`.`dim_applications`.`corever` IN (1, 2, 3, 4))) OR ((`dim`.`dim_applications`.`product_id` != 3366) AND (`dim`.`dim_applications`.`corever` IN (1, 2, 3)))) `b` ON `a`.`app_name` = `b`.`app_name`;